window.VIRAL_TOPICS=[{"slug":"general","title":{"en":"General Principles","ar":"المبادئ العامة"},"count":5,"types":{"MCQ":5},"summary":{"en":"Viral lesion morphology, DNA and RNA groups, diagnostic confirmation, and when supportive or targeted antiviral care is appropriate.","ar":"أشكال الآفات الفيروسية ومجموعات DNA وRNA وتأكيد التشخيص ومتى تكفي الرعاية الداعمة أو يلزم علاج مضاد للفيروسات."},"pearl":{"en":"Start with the primary lesion, then use distribution, host risk, and systemic findings to narrow the virus.","ar":"ابدأ بنوع الآفة الأولية ثم استخدم التوزيع وخطورة المريض والأعراض الجهازية لتحديد الفيروس."},"image":"assets/images/chapters/viral/viral-01.webp"},{"slug":"herpes-simplex","title":{"en":"Herpes Simplex","ar":"الهربس البسيط"},"count":22,"types":{"MCQ":7,"Case":6,"Treatment":7,"Image":2},"summary":{"en":"Latency, primary gingivostomatitis, recurrent disease, eczema herpeticum, antiviral regimens, and toxicity prevention.","ar":"الكمون والتهاب الفم واللثة الأولي والعدوى المتكررة والإكزيما الهربسية وأنظمة العلاج والوقاية من السمية."},"pearl":{"en":"Grouped painful vesicles plus recurrence near the same sensory distribution strongly suggest HSV reactivation.","ar":"الحويصلات المؤلمة المتجمعة مع التكرار قرب التوزيع العصبي نفسه ترجح إعادة تنشيط HSV."},"image":"assets/images/chapters/viral/viral-q136.webp"},{"slug":"varicella","title":{"en":"Varicella","ar":"الجديري المائي"},"count":17,"types":{"MCQ":6,"Case":5,"Treatment":5,"Image":1},"summary":{"en":"Successive lesion crops, infectivity, isolation, risk groups, symptomatic care, and oral versus IV antiviral selection.","ar":"دفعات الآفات وفترة العدوى والعزل والفئات عالية الخطورة والرعاية العرضية واختيار العلاج الفموي أو الوريدي."},"pearl":{"en":"Lesions at several stages at the same time are a classic clue to successive varicella crops.","ar":"وجود آفات بمراحل مختلفة في الوقت نفسه علامة كلاسيكية لدفعات الجديري المائي."},"image":"assets/images/chapters/viral/viral-q138.webp"},{"slug":"herpes-zoster","title":{"en":"Herpes Zoster","ar":"الحزام الناري"},"count":22,"types":{"MCQ":6,"Case":7,"Treatment":7,"Image":2},"summary":{"en":"Dermatomal pain and vesicles, ophthalmic and otic warning signs, postherpetic neuralgia, and early antiviral therapy.","ar":"الألم والحويصلات القطاعية وعلامات الخطر العينية والأذنية والألم العصبي التالي للهربس والعلاج المبكر."},"pearl":{"en":"Pain can precede the rash; nasal-tip or ear vesicles change the urgency of referral.","ar":"قد يسبق الألم الطفح، وحويصلات طرف الأنف أو الأذن تغير درجة الاستعجال في الإحالة."},"image":"assets/images/chapters/viral/viral-q139.webp"},{"slug":"hpv","title":{"en":"Human Papillomavirus","ar":"فيروس الورم الحليمي البشري"},"count":24,"types":{"MCQ":8,"Case":7,"Treatment":7,"Image":2},"summary":{"en":"Cutaneous and genital wart patterns, low- and high-risk HPV types, treatment choices, biopsy clues, and prevention.","ar":"أنماط الثآليل الجلدية والتناسلية والأنواع منخفضة وعالية الخطورة وخيارات العلاج وعلامات الخزعة والوقاية."},"pearl":{"en":"Wart location and morphology guide treatment, but atypical pigmented or ulcerated lesions may need biopsy.","ar":"يوجه مكان الثؤلول وشكله العلاج، لكن الآفات المصطبغة أو المتقرحة غير النمطية قد تحتاج خزعة."},"image":"assets/images/chapters/viral/viral-q141.webp"},{"slug":"hfmd-herpangina","title":{"en":"HFMD and Herpangina","ar":"مرض اليد والقدم والفم والهربانجينا"},"count":14,"types":{"MCQ":5,"Case":5,"Treatment":3,"Image":1},"summary":{"en":"Enteroviral oral and acral patterns, differentiation from herpangina, hydration, infection control, and neurologic red flags.","ar":"الأنماط الفموية والطرفية للفيروسات المعوية والتفريق عن الهربانجينا والترطيب ومنع الانتقال وعلامات الخطر العصبية."},"pearl":{"en":"Oral lesions plus hand and foot lesions favor HFMD; posterior oral disease alone favors herpangina.","ar":"الآفات الفموية مع اليدين والقدمين ترجح HFMD، بينما الآفات الخلفية بالفم دون طفح طرفي ترجح الهربانجينا."},"image":"assets/images/chapters/viral/viral-q143.webp"},{"slug":"measles","title":{"en":"Measles","ar":"الحصبة"},"count":15,"types":{"MCQ":6,"Case":5,"Treatment":3,"Image":1},"summary":{"en":"The three-C prodrome, Koplik spots, descending rash, airborne isolation, vitamin A, complications, and vaccination.","ar":"الثلاثية البادرية وبقع كوبليك وانتشار الطفح والعزل الهوائي وفيتامين أ والمضاعفات والتطعيم."},"pearl":{"en":"Suspected measles requires immediate airborne isolation before confirmation.","ar":"الاشتباه في الحصبة يستلزم العزل الهوائي فورًا قبل التأكيد."},"image":"assets/images/chapters/viral/viral-q144.webp"},{"slug":"rubella","title":{"en":"Rubella","ar":"الحصبة الألمانية"},"count":6,"types":{"MCQ":3,"Case":2,"Treatment":1},"summary":{"en":"Postauricular and suboccipital nodes, mild exanthem, congenital risk, pregnancy counseling, and MMR prevention.","ar":"العقد خلف الأذن وتحت القذال والطفح الخفيف وخطر العدوى الخلقية وإرشاد الحامل والوقاية بلقاح MMR."},"pearl":{"en":"A mild rash can carry major fetal consequences, so pregnancy status is central to the decision.","ar":"قد يكون الطفح خفيفًا لكن العواقب على الجنين كبيرة، لذلك حالة الحمل أساسية في القرار."},"image":"assets/images/chapters/viral/viral-05.webp"},{"slug":"fifth-disease","title":{"en":"Fifth Disease","ar":"المرض الخامس"},"count":7,"types":{"MCQ":3,"Case":2,"Treatment":1,"Image":1},"summary":{"en":"Slapped-cheek and lacy rash patterns, hematologic complications, pregnancy risk, and supportive management.","ar":"طفح الخدين كالصفعة والطفح الشبكي والمضاعفات الدموية وخطر الحمل والتدبير الداعم."},"pearl":{"en":"The rash often appears after peak contagiousness, but anemia and pregnancy risks still matter.","ar":"غالبًا يظهر الطفح بعد ذروة العدوى، لكن مخاطر الأنيميا والحمل تظل مهمة."},"image":"assets/images/chapters/viral/viral-q145.webp"},{"slug":"molluscum","title":{"en":"Molluscum Contagiosum","ar":"المليساء المعدية"},"count":9,"types":{"MCQ":4,"Case":3,"Treatment":1,"Image":1},"summary":{"en":"Umbilicated papules, transmission, eczema association, immune-status clues, observation, and procedural options.","ar":"الحطاطات المنقرة والانتقال والارتباط بالإكزيما ودلالات المناعة والملاحظة والخيارات الإجرائية."},"pearl":{"en":"Central umbilication is the key clue; extensive adult disease should prompt assessment of immune status.","ar":"التنقر المركزي هو العلامة الأهم، والانتشار الواسع لدى البالغ يستدعي تقييم المناعة."},"image":"assets/images/chapters/viral/viral-q146.webp"},{"slug":"covid-cutaneous","title":{"en":"COVID-19 Cutaneous Signs","ar":"العلامات الجلدية لكوفيد-19"},"count":9,"types":{"MCQ":2,"Case":3,"Image":4},"summary":{"en":"Morbilliform, urticarial, vesicular, vascular, and pernio-like patterns with medication and severity differentials.","ar":"الأنماط الشبيهة بالحصبة والشرية والحويصلية والوعائية والشبيهة بالشرث مع التفريق الدوائي وتقييم الشدة."},"pearl":{"en":"Skin findings are contextual and nonspecific; always consider drugs, vascular severity, and alternative diagnoses.","ar":"العلامات الجلدية سياقية وغير نوعية؛ راجع الأدوية والشدة الوعائية والتشخيصات البديلة."},"image":"assets/images/chapters/viral/viral-q150.webp"}];
