window.VIRAL_QUESTIONS=[{"id":"Q001","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 103","question":{"en":"Which lesion pattern is most characteristic of herpes simplex, varicella, zoster, and hand-foot-and-mouth disease?","ar":"ما نمط الآفات الأكثر تميزًا للهربس البسيط والجديري المائي والحزام الناري ومرض اليد والقدم والفم؟"},"options":[{"letter":"A","en":"Vesicular","ar":"حويصلي"},{"letter":"B","en":"Papular only","ar":"حطاطي فقط"},{"letter":"C","en":"Purpuric only","ar":"فرفري فقط"},{"letter":"D","en":"Ulcerative only","ar":"تقرحي فقط"}],"correct":"A","explanation":{"en":"These viral diseases commonly produce vesicles, although their distribution and associated symptoms differ.","ar":"تُنتج هذه الأمراض الفيروسية عادةً حويصلات، مع اختلاف التوزيع والأعراض المصاحبة."},"reasoning":{"en":"Recognizing the primary lesion type narrows the differential before considering distribution, age, and systemic findings.","ar":"تحديد نوع الآفة الأولية يضيّق التشخيصات المحتملة قبل تقييم التوزيع والعمر والأعراض الجهازية."},"image":null},{"id":"Q002","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 104","question":{"en":"Which virus group is correctly classified as a DNA virus?","ar":"أي مجموعة فيروسية مصنفة بصورة صحيحة كفيروسات DNA؟"},"options":[{"letter":"A","en":"Herpesviruses","ar":"فيروسات الهربس"},{"letter":"B","en":"Paramyxoviruses","ar":"الفيروسات المخاطية"},{"letter":"C","en":"Picornaviruses","ar":"البيكورنا"},{"letter":"D","en":"Parvovirus B19 only as an RNA virus","ar":"بارفو B19 كفيروس RNA"}],"correct":"A","explanation":{"en":"Herpesviruses, poxviruses, and papillomaviruses are DNA viruses.","ar":"فيروسات الهربس والجدري والورم الحليمي هي فيروسات DNA."},"reasoning":{"en":"Classifying the virus helps predict replication strategy, latency, and the role of antiviral therapy.","ar":"تصنيف الفيروس يساعد على توقع طريقة التكاثر والكمون ودور العلاج المضاد للفيروسات."},"image":null},{"id":"Q003","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 103","question":{"en":"Which diagnostic method is generally most sensitive for confirming an atypical viral vesicular eruption?","ar":"ما الفحص الأكثر حساسية عمومًا لتأكيد طفح فيروسي حويصلي غير نمطي؟"},"options":[{"letter":"A","en":"PCR","ar":"تفاعل البوليميراز المتسلسل"},{"letter":"B","en":"Gram stain","ar":"صبغة غرام"},{"letter":"C","en":"Routine bacterial culture","ar":"مزرعة بكتيرية روتينية"},{"letter":"D","en":"Patch testing","ar":"اختبار الرقعة"}],"correct":"A","explanation":{"en":"PCR directly detects viral nucleic acid and is especially useful when morphology is atypical.","ar":"يكشف PCR المادة الوراثية الفيروسية مباشرةً ويكون مفيدًا خصوصًا عند عدم نمطية الشكل السريري."},"reasoning":{"en":"Atypical lesions require a test that is rapid, specific, and remains useful across lesion stages.","ar":"الآفات غير النمطية تحتاج فحصًا سريعًا ونوعيًا وفعالًا عبر مراحل الآفة المختلفة."},"image":null},{"id":"Q004","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 104","question":{"en":"Which condition is primarily papular or nodular rather than maculopapular?","ar":"أي حالة تكون أساسًا حطاطية أو عقيدية وليست بقعية حطاطية؟"},"options":[{"letter":"A","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"B","en":"Measles","ar":"الحصبة"},{"letter":"C","en":"Rubella","ar":"الحصبة الألمانية"},{"letter":"D","en":"Erythema infectiosum","ar":"المرض الخامس"}],"correct":"A","explanation":{"en":"Molluscum contagiosum produces discrete umbilicated papules; the other choices are exanthematous illnesses.","ar":"تُحدث المليساء المعدية حطاطات منفصلة ذات تنقر مركزي، بينما الخيارات الأخرى أمراض طفحية جهازية."},"reasoning":{"en":"The morphology separates localized viral proliferations from systemic viral exanthems.","ar":"يفصل شكل الآفات بين التكاثرات الفيروسية الموضعية والطفوح الفيروسية الجهازية."},"image":null},{"id":"Q005","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 103","question":{"en":"Which statement best describes treatment of most viral skin diseases?","ar":"أي عبارة تصف علاج معظم الأمراض الجلدية الفيروسية بدقة؟"},"options":[{"letter":"A","en":"Many are self-limited; antivirals are reserved for selected infections or high-risk patients","ar":"كثير منها محدود ذاتيًا وتُحجز مضادات الفيروسات لحالات مختارة أو عالية الخطورة"},{"letter":"B","en":"All require systemic antibiotics","ar":"جميعها تحتاج مضادات حيوية جهازية"},{"letter":"C","en":"All require surgical removal","ar":"جميعها تحتاج استئصالًا جراحيًا"},{"letter":"D","en":"Corticosteroids are first-line for every viral rash","ar":"الكورتيزون هو الخط الأول لكل طفح فيروسي"}],"correct":"A","explanation":{"en":"Supportive care is sufficient for many viral eruptions, while HSV and VZV may require targeted antiviral treatment.","ar":"تكفي الرعاية الداعمة لكثير من الطفوح الفيروسية، بينما قد يحتاج HSV وVZV علاجًا مضادًا للفيروسات."},"reasoning":{"en":"Treatment is guided by the virus, severity, host immunity, site, and complication risk.","ar":"يُحدد العلاج حسب نوع الفيروس والشدة ومناعة المريض والمكان وخطر المضاعفات."},"image":null},{"id":"Q006","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 105","question":{"en":"After primary HSV infection, where does the virus remain latent?","ar":"أين يبقى فيروس الهربس البسيط كامنًا بعد العدوى الأولية؟"},"options":[{"letter":"A","en":"Sensory ganglia","ar":"العقد العصبية الحسية"},{"letter":"B","en":"Bone marrow only","ar":"نخاع العظم فقط"},{"letter":"C","en":"Renal tubules","ar":"الأنابيب الكلوية"},{"letter":"D","en":"Epidermis permanently","ar":"البشرة بصورة دائمة"}],"correct":"A","explanation":{"en":"HSV establishes latency in sensory ganglia and reactivates along sensory nerves.","ar":"يستقر HSV كامنًا في العقد العصبية الحسية ثم يُعاد تنشيطه عبر الأعصاب الحسية."},"reasoning":{"en":"Latency explains recurrent lesions at or near the same anatomic site.","ar":"يفسر الكمون تكرار الآفات في المكان نفسه أو بالقرب منه."},"image":null},{"id":"Q007","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 106","question":{"en":"Which finding is most typical of primary herpetic gingivostomatitis in a young child?","ar":"أي علامة هي الأكثر نموذجية لالتهاب اللثة والفم الهربسي الأولي لدى طفل صغير؟"},"options":[{"letter":"A","en":"Painful oral vesicles with inflamed bleeding gums and fever","ar":"حويصلات فموية مؤلمة مع التهاب ونزف اللثة وحمى"},{"letter":"B","en":"Painless oral plaques that scrape off","ar":"لويحات فموية غير مؤلمة تُمسح بسهولة"},{"letter":"C","en":"Single painless chancre","ar":"قرحة واحدة غير مؤلمة"},{"letter":"D","en":"Isolated dry cough without oral lesions","ar":"سعال جاف منفرد دون آفات فموية"}],"correct":"A","explanation":{"en":"Primary HSV-1 gingivostomatitis causes fever, tender nodes, gingivitis, and painful vesicles or ulcers.","ar":"يسبب التهاب الفم واللثة الأولي بـHSV-1 حمى وعقدًا مؤلمة والتهاب لثة وحويصلات أو قرحًا مؤلمة."},"reasoning":{"en":"The combination of systemic illness, gingivitis, and diffuse painful oral lesions distinguishes it from localized recurrent herpes.","ar":"اجتماع الأعراض الجهازية والتهاب اللثة والآفات الفموية المؤلمة المنتشرة يميزه عن الهربس المتكرر الموضعي."},"image":null},{"id":"Q008","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 107","question":{"en":"Which HSV complication is especially associated with atopic dermatitis?","ar":"ما مضاعفة HSV المرتبطة بصورة خاصة بالتهاب الجلد التأتبي؟"},"options":[{"letter":"A","en":"Eczema herpeticum","ar":"الإكزيما الهربسية"},{"letter":"B","en":"Erythema infectiosum","ar":"المرض الخامس"},{"letter":"C","en":"Plantar wart","ar":"الثؤلول الأخمصي"},{"letter":"D","en":"Molluscum dermatitis only","ar":"التهاب جلد المليساء فقط"}],"correct":"A","explanation":{"en":"Eczema herpeticum is disseminated HSV occurring over compromised atopic skin.","ar":"الإكزيما الهربسية هي انتشار HSV على جلد متضرر بسبب الإكزيما التأتبية."},"reasoning":{"en":"Widespread monomorphic vesicles with fever in an atopic patient are an antiviral emergency.","ar":"الحويصلات المتشابهة المنتشرة مع الحمى لدى مريض تأتبي تمثل حالة عاجلة للعلاج المضاد للفيروسات."},"image":null},{"id":"Q009","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 107","question":{"en":"Which feature is most consistent with recurrent herpes labialis rather than primary infection?","ar":"أي سمة تتوافق أكثر مع الهربس الشفوي المتكرر مقارنة بالعدوى الأولية؟"},"options":[{"letter":"A","en":"Localized tingling followed by small clustered vesicles without systemic symptoms","ar":"وخز موضعي يتبعه حويصلات صغيرة متجمعة دون أعراض جهازية"},{"letter":"B","en":"Diffuse gingivitis and high fever for two weeks","ar":"التهاب لثة منتشر وحمى مرتفعة لأسبوعين"},{"letter":"C","en":"Generalized polymorphic rash","ar":"طفح متعدد الأشكال منتشر"},{"letter":"D","en":"Painless umbilicated papules","ar":"حطاطات منقرة غير مؤلمة"}],"correct":"A","explanation":{"en":"Recurrent herpes is shorter, localized, and usually lacks systemic symptoms.","ar":"يكون الهربس المتكرر أقصر مدة وموضعيًا وغالبًا دون أعراض جهازية."},"reasoning":{"en":"The prodromal tingling and localized recurrence reflect reactivation from a sensory ganglion.","ar":"الوخز البادري والتكرار الموضعي يعكسان إعادة التنشيط من عقدة عصبية حسية."},"image":null},{"id":"Q010","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 108","question":{"en":"What is the principal antiviral mechanism of acyclovir, valacyclovir, and famciclovir?","ar":"ما الآلية الرئيسية لأسيكلوفير وفالاسيكلوفير وفامسيكلوفير؟"},"options":[{"letter":"A","en":"Inhibition of viral DNA polymerase","ar":"تثبيط بوليميراز DNA الفيروسي"},{"letter":"B","en":"Inhibition of bacterial cell-wall synthesis","ar":"تثبيط تصنيع جدار الخلية البكتيرية"},{"letter":"C","en":"Neutralization of histamine","ar":"معادلة الهيستامين"},{"letter":"D","en":"Inhibition of fungal ergosterol synthesis","ar":"تثبيط تصنيع الإرجوستيرول الفطري"}],"correct":"A","explanation":{"en":"These nucleoside analogues inhibit viral DNA synthesis after activation in infected cells.","ar":"تثبط نظائر النيوكليوزيد هذه تصنيع DNA الفيروسي بعد تنشيطها داخل الخلايا المصابة."},"reasoning":{"en":"The mechanism explains their activity against replicating herpesviruses, not latent virus.","ar":"تفسر الآلية فعاليتها ضد فيروس الهربس المتكاثر وليس الفيروس الكامن."},"image":null},{"id":"Q011","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 108","question":{"en":"Which oral regimen is listed for one-day episodic treatment of recurrent herpes labialis?","ar":"أي نظام فموي مذكور كعلاج نوباتي ليوم واحد للهربس الشفوي المتكرر؟"},"options":[{"letter":"A","en":"Valacyclovir 2 g twice in one day","ar":"فالاسيكلوفير 2 جم مرتين في يوم واحد"},{"letter":"B","en":"Acyclovir 200 mg once monthly","ar":"أسيكلوفير 200 مجم مرة شهريًا"},{"letter":"C","en":"Amoxicillin 1 g twice daily","ar":"أموكسيسيلين 1 جم مرتين يوميًا"},{"letter":"D","en":"Fluconazole 150 mg once","ar":"فلوكونازول 150 مجم جرعة واحدة"}],"correct":"A","explanation":{"en":"Valacyclovir 2 g twice daily for one day is an episodic regimen when begun very early.","ar":"فالاسيكلوفير 2 جم مرتين خلال يوم واحد نظام نوباتي عند البدء مبكرًا جدًا."},"reasoning":{"en":"Short episodic regimens depend on treatment during the prodrome or within the first 48 hours.","ar":"تعتمد الأنظمة القصيرة على بدء العلاج في الطور البادري أو خلال أول 48 ساعة."},"image":null},{"id":"Q012","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"MCQ","difficulty":"Easy","source":"PDF p. 110","question":{"en":"Which adverse effect requires hydration and renal dose adjustment during IV acyclovir therapy?","ar":"أي أثر جانبي يستلزم الترطيب وضبط الجرعة حسب الكلى أثناء أسيكلوفير الوريدي؟"},"options":[{"letter":"A","en":"Crystal-associated kidney injury","ar":"إصابة كلوية مرتبطة بترسب البلورات"},{"letter":"B","en":"Irreversible deafness in all patients","ar":"صمم غير عكوس لدى جميع المرضى"},{"letter":"C","en":"Severe hypoglycemia","ar":"هبوط سكر شديد"},{"letter":"D","en":"Pulmonary fibrosis","ar":"تليف رئوي"}],"correct":"A","explanation":{"en":"Acyclovir can crystallize in renal tubules, especially with dehydration, rapid infusion, or inadequate dose adjustment.","ar":"قد يترسب أسيكلوفير في الأنابيب الكلوية خاصة مع الجفاف أو التسريب السريع أو عدم ضبط الجرعة."},"reasoning":{"en":"Renal monitoring, adequate hydration, and slow infusion reduce preventable toxicity.","ar":"تقلل متابعة وظائف الكلى والترطيب الكافي والتسريب البطيء السمية القابلة للوقاية."},"image":null},{"id":"Q013","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 112","question":{"en":"Which rash description is classic for primary varicella?","ar":"أي وصف للطفح يُعد نموذجيًا للجديري المائي الأولي؟"},"options":[{"letter":"A","en":"Successive crops with macules, papules, vesicles, and crusts present together","ar":"دفعات متتالية مع وجود بقع وحطاطات وحويصلات وقشور معًا"},{"letter":"B","en":"Single dermatomal band that never crosses the midline","ar":"شريط جلدي عصبي واحد لا يعبر الخط المتوسط"},{"letter":"C","en":"Only plantar hyperkeratotic papules","ar":"حطاطات متقرنة أخمصية فقط"},{"letter":"D","en":"Fixed target lesions only","ar":"آفات هدفية ثابتة فقط"}],"correct":"A","explanation":{"en":"Varicella produces a polymorphic eruption because lesions appear in successive crops.","ar":"ينتج الجديري المائي طفحًا متعدد المراحل لأن الآفات تظهر في دفعات متتالية."},"reasoning":{"en":"Simultaneous lesions at different stages help distinguish varicella from many other vesicular eruptions.","ar":"وجود آفات بمراحل مختلفة في الوقت نفسه يساعد على تمييز الجديري المائي عن طفوح حويصلية أخرى."},"image":null},{"id":"Q014","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 113","question":{"en":"For how long is a patient with varicella generally infectious?","ar":"إلى متى يكون مريض الجديري المائي معديًا عادةً؟"},"options":[{"letter":"A","en":"From about 48 hours before rash until all lesions are crusted","ar":"من نحو 48 ساعة قبل الطفح حتى تقشر جميع الآفات"},{"letter":"B","en":"Only after all lesions crust","ar":"فقط بعد تقشر جميع الآفات"},{"letter":"C","en":"Only during the incubation period","ar":"فقط خلال فترة الحضانة"},{"letter":"D","en":"For life regardless of lesions","ar":"مدى الحياة بغض النظر عن الآفات"}],"correct":"A","explanation":{"en":"Varicella transmission begins before the rash and continues until every lesion has crusted.","ar":"يبدأ انتقال الجديري المائي قبل ظهور الطفح ويستمر حتى تتقشر كل الآفات."},"reasoning":{"en":"This timing determines isolation, school exclusion, and protection of high-risk contacts.","ar":"يحدد هذا التوقيت العزل والابتعاد عن المدرسة وحماية المخالطين عاليي الخطورة."},"image":null},{"id":"Q015","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 114","question":{"en":"Which distribution is most typical of chickenpox?","ar":"أي توزيع هو الأكثر نموذجية للجديري المائي؟"},"options":[{"letter":"A","en":"Centripetal, with more lesions on trunk and face than extremities","ar":"مركزي مع آفات أكثر على الجذع والوجه من الأطراف"},{"letter":"B","en":"Only palms and soles","ar":"راحة اليدين وأخمص القدمين فقط"},{"letter":"C","en":"Strictly unilateral dermatome","ar":"قطاع جلدي عصبي أحادي الجانب فقط"},{"letter":"D","en":"Only genital mucosa","ar":"الغشاء المخاطي التناسلي فقط"}],"correct":"A","explanation":{"en":"The varicella rash is centripetal, predominating on the trunk and face.","ar":"يكون طفح الجديري المائي مركزي التوزيع ويغلب على الجذع والوجه."},"reasoning":{"en":"Distribution plus lesion polymorphism strongly supports the diagnosis.","ar":"يدعم التوزيع مع تعدد مراحل الآفات التشخيص بقوة."},"image":null},{"id":"Q016","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 115","question":{"en":"Which medication should be avoided in a child with varicella because of the risk of Reye syndrome?","ar":"أي دواء يجب تجنبه لدى طفل مصاب بالجديري المائي بسبب خطر متلازمة راي؟"},"options":[{"letter":"A","en":"Aspirin","ar":"الأسبرين"},{"letter":"B","en":"Paracetamol","ar":"الباراسيتامول"},{"letter":"C","en":"Calamine lotion","ar":"لوشن الكالامين"},{"letter":"D","en":"Oral antihistamine","ar":"مضاد هيستامين فموي"}],"correct":"A","explanation":{"en":"Salicylate exposure during viral illness is associated with Reye syndrome.","ar":"يرتبط استخدام الساليسيلات أثناء العدوى الفيروسية بمتلازمة راي."},"reasoning":{"en":"Fever should be managed with safer alternatives such as paracetamol while avoiding aspirin.","ar":"تُعالج الحمى ببدائل أكثر أمانًا مثل الباراسيتامول مع تجنب الأسبرين."},"image":null},{"id":"Q017","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 116","question":{"en":"Which group should routinely receive antiviral therapy for uncomplicated varicella according to the chapter?","ar":"أي مجموعة ينبغي أن تتلقى علاجًا مضادًا للفيروسات بصورة روتينية للجديري المائي غير المعقد وفق الفصل؟"},"options":[{"letter":"A","en":"Immunocompetent adults","ar":"البالغون ذوو المناعة السليمة"},{"letter":"B","en":"Every healthy child younger than 12 years","ar":"كل طفل سليم أصغر من 12 سنة"},{"letter":"C","en":"Only vaccinated toddlers","ar":"الأطفال المطعمون فقط"},{"letter":"D","en":"No patient with active lesions","ar":"لا مريض لديه آفات نشطة"}],"correct":"A","explanation":{"en":"Adults have a higher risk of severe varicella and pneumonia, so oral antiviral treatment is recommended.","ar":"يتعرض البالغون لخطر أعلى للجديري الشديد والالتهاب الرئوي، لذلك يُوصى بالعلاج الفموي المضاد للفيروسات."},"reasoning":{"en":"Age changes the risk-benefit balance even when disease initially appears uncomplicated.","ar":"يغير العمر موازنة الفائدة والمخاطر حتى إن بدا المرض غير معقد في البداية."},"image":null},{"id":"Q018","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"MCQ","difficulty":"Easy","source":"PDF p. 117","question":{"en":"What is the preferred treatment for complicated or significantly immunocompromised varicella?","ar":"ما العلاج المفضل للجديري المائي المعقد أو لدى مريض مثبط المناعة بدرجة مهمة؟"},"options":[{"letter":"A","en":"IV acyclovir","ar":"أسيكلوفير وريدي"},{"letter":"B","en":"Topical salicylic acid","ar":"حمض الساليسيليك موضعيًا"},{"letter":"C","en":"Oral penicillin alone","ar":"بنسلين فموي فقط"},{"letter":"D","en":"No treatment until crusting","ar":"عدم العلاج حتى التقشر"}],"correct":"A","explanation":{"en":"IV acyclovir provides reliable systemic exposure for severe or immunocompromised cases.","ar":"يوفر أسيكلوفير الوريدي تعرضًا جهازيًا موثوقًا في الحالات الشديدة أو المثبطة للمناعة."},"reasoning":{"en":"High-risk patients can deteriorate rapidly and require prompt parenteral therapy and monitoring.","ar":"قد يتدهور المرضى عالي الخطورة سريعًا ويحتاجون علاجًا وريديًا ومتابعة مبكرة."},"image":null},{"id":"Q019","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Easy","source":"PDF p. 119","question":{"en":"What is the cause of herpes zoster?","ar":"ما سبب الحزام الناري؟"},"options":[{"letter":"A","en":"Reactivation of latent VZV","ar":"إعادة تنشيط فيروس VZV الكامن"},{"letter":"B","en":"Primary infection with HPV","ar":"عدوى أولية بفيروس HPV"},{"letter":"C","en":"Bacterial invasion of a dermatome","ar":"غزو بكتيري لقطاع جلدي"},{"letter":"D","en":"New infection with measles virus","ar":"عدوى جديدة بفيروس الحصبة"}],"correct":"A","explanation":{"en":"Herpes zoster results from reactivation of VZV in a sensory ganglion after previous varicella.","ar":"ينتج الحزام الناري من إعادة تنشيط VZV في عقدة عصبية حسية بعد جديري سابق."},"reasoning":{"en":"The ganglionic origin explains the unilateral dermatomal pain and eruption.","ar":"يفسر المنشأ العقدي الألم والطفح أحادي الجانب وفق القطاع العصبي."},"image":null},{"id":"Q020","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Easy","source":"PDF p. 120","question":{"en":"Which feature most strongly supports uncomplicated herpes zoster?","ar":"أي سمة تدعم بقوة تشخيص الحزام الناري غير المعقد؟"},"options":[{"letter":"A","en":"Unilateral grouped vesicles limited to a dermatome with preceding burning pain","ar":"حويصلات متجمعة أحادية الجانب ضمن قطاع عصبي مع ألم حارق سابق"},{"letter":"B","en":"Diffuse nonpruritic rash beginning at the hairline","ar":"طفح منتشر غير حاك يبدأ عند خط الشعر"},{"letter":"C","en":"Symmetric slapped-cheek erythema","ar":"احمرار متناظر كصفعة على الخدين"},{"letter":"D","en":"Painless pearly umbilicated papules","ar":"حطاطات لؤلؤية منقرة غير مؤلمة"}],"correct":"A","explanation":{"en":"Dermatomal vesicles preceded by neuropathic pain are typical of zoster.","ar":"الحويصلات القطاعية التي يسبقها ألم عصبي نموذجية للحزام الناري."},"reasoning":{"en":"Pain localization before rash often provides the earliest diagnostic clue.","ar":"يوفر تموضع الألم قبل الطفح أول دليل تشخيصي في كثير من الأحيان."},"image":null},{"id":"Q021","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Medium","source":"PDF p. 120","question":{"en":"How is postherpetic neuralgia defined in the chapter?","ar":"كيف يُعرّف الألم العصبي التالي للهربس في الفصل؟"},"options":[{"letter":"A","en":"Pain persisting at least 90 days after rash onset","ar":"ألم يستمر 90 يومًا على الأقل بعد بدء الطفح"},{"letter":"B","en":"Pain only during the first 24 hours","ar":"ألم خلال أول 24 ساعة فقط"},{"letter":"C","en":"Any itch before rash","ar":"أي حكة قبل الطفح"},{"letter":"D","en":"Muscle pain without previous rash","ar":"ألم عضلي دون طفح سابق"}],"correct":"A","explanation":{"en":"PHN is persistent neuropathic pain lasting 90 days or longer after the zoster rash begins.","ar":"الألم العصبي التالي للهربس هو ألم عصبي يستمر 90 يومًا أو أكثر بعد بدء طفح الحزام الناري."},"reasoning":{"en":"The time threshold distinguishes prolonged neuropathy from ordinary acute neuritis.","ar":"يفصل الحد الزمني الاعتلال العصبي المستمر عن التهاب العصب الحاد المعتاد."},"image":null},{"id":"Q022","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Medium","source":"PDF p. 121","question":{"en":"Vesicles on the tip of the nose in a patient with zoster are a warning for involvement of which structure?","ar":"الحويصلات على طرف الأنف لدى مريض بالحزام الناري تحذر من إصابة أي عضو؟"},"options":[{"letter":"A","en":"Eye","ar":"العين"},{"letter":"B","en":"Kidney","ar":"الكلية"},{"letter":"C","en":"Knee joint","ar":"مفصل الركبة"},{"letter":"D","en":"Pancreas","ar":"البنكرياس"}],"correct":"A","explanation":{"en":"Nasal-tip lesions suggest nasociliary involvement and increased risk of herpes zoster ophthalmicus.","ar":"تشير آفات طرف الأنف إلى إصابة العصب الأنفي الهدبي وزيادة خطر الهربس العيني."},"reasoning":{"en":"This sign should trigger urgent ophthalmologic assessment because vision-threatening disease may be present.","ar":"تستلزم هذه العلامة تقييمًا عاجلًا للعين لاحتمال وجود مرض مهدد للبصر."},"image":null},{"id":"Q023","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Medium","source":"PDF p. 121","question":{"en":"Which triad defines Ramsay Hunt syndrome?","ar":"أي ثلاثية تعرّف متلازمة رامزي هانت؟"},"options":[{"letter":"A","en":"Ear pain, auricular/canal vesicles, and ipsilateral facial paralysis","ar":"ألم الأذن وحويصلات بالقناة أو الصيوان وشلل وجهي في الجهة نفسها"},{"letter":"B","en":"Cough, conjunctivitis, and Koplik spots","ar":"سعال والتهاب ملتحمة وبقع كوبليك"},{"letter":"C","en":"Fever, slapped cheeks, and arthritis","ar":"حمى وخدود مصعوفة والتهاب مفاصل"},{"letter":"D","en":"Genital ulcers, dysuria, and urethritis only","ar":"قرح تناسلية وعسر تبول والتهاب إحليل فقط"}],"correct":"A","explanation":{"en":"Ramsay Hunt syndrome is zoster oticus with ear pain, vesicles, and facial nerve palsy.","ar":"متلازمة رامزي هانت هي هربس أذني يترافق مع ألم الأذن والحويصلات وشلل العصب الوجهي."},"reasoning":{"en":"Recognizing the triad permits early combined antiviral and anti-inflammatory treatment.","ar":"التعرف على الثلاثية يسمح بالعلاج المبكر المضاد للفيروسات والمضاد للالتهاب."},"image":null},{"id":"Q024","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"MCQ","difficulty":"Medium","source":"PDF p. 122","question":{"en":"What is the gold-standard laboratory test for atypical herpes zoster?","ar":"ما الفحص المخبري المعياري الذهبي للحزام الناري غير النمطي؟"},"options":[{"letter":"A","en":"PCR from lesion material","ar":"PCR من مادة الآفة"},{"letter":"B","en":"Tuberculin skin test","ar":"اختبار التوبركولين"},{"letter":"C","en":"Routine stool culture","ar":"مزرعة براز روتينية"},{"letter":"D","en":"Serum uric acid","ar":"حمض اليوريك بالدم"}],"correct":"A","explanation":{"en":"PCR is highly sensitive, specific, rapid, and useful for vesicles, ulcers, or crusts.","ar":"يتميز PCR بحساسية ونوعية وسرعة عالية ويمكن استخدامه مع الحويصلات أو القرح أو القشور."},"reasoning":{"en":"It is preferred when clinical morphology is atypical or HSV must be distinguished from VZV.","ar":"يُفضل عندما يكون الشكل غير نمطي أو يلزم التفريق بين HSV وVZV."},"image":null},{"id":"Q025","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 128","question":{"en":"Which HPV types are most commonly associated with genital warts?","ar":"ما أنماط HPV الأكثر ارتباطًا بالثآليل التناسلية؟"},"options":[{"letter":"A","en":"6 and 11","ar":"6 و11"},{"letter":"B","en":"16 and 18 only","ar":"16 و18 فقط"},{"letter":"C","en":"1 and 2","ar":"1 و2"},{"letter":"D","en":"3 and 10","ar":"3 و10"}],"correct":"A","explanation":{"en":"HPV 6 and 11 are low-risk types responsible for most condyloma acuminata.","ar":"يُعد النمطان 6 و11 منخفضي الخطورة مسؤولين عن معظم الثآليل التناسلية."},"reasoning":{"en":"Separating low-risk wart-causing types from oncogenic types is central to counseling and screening.","ar":"الفصل بين الأنماط المسببة للثآليل منخفضة الخطورة والأنماط المسرطنة أساسي للتوعية والفحص."},"image":null},{"id":"Q026","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 128","question":{"en":"Which HPV types are strongly linked to cervical and anal cancers?","ar":"ما أنماط HPV المرتبطة بقوة بسرطان عنق الرحم والشرج؟"},"options":[{"letter":"A","en":"16 and 18","ar":"16 و18"},{"letter":"B","en":"6 and 11","ar":"6 و11"},{"letter":"C","en":"1 and 4","ar":"1 و4"},{"letter":"D","en":"3 and 10","ar":"3 و10"}],"correct":"A","explanation":{"en":"HPV 16 and 18 are high-risk oncogenic types.","ar":"النمطان 16 و18 من الأنماط عالية الخطورة المسرطنة."},"reasoning":{"en":"Cancer-risk typing affects vaccination, screening, and follow-up even when visible warts are absent.","ar":"يؤثر تحديد الأنماط المسرطنة في التطعيم والفحص والمتابعة حتى دون وجود ثآليل ظاهرة."},"image":null},{"id":"Q027","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 128","question":{"en":"Which morphology is most typical of condyloma acuminata?","ar":"أي شكل هو الأكثر نموذجية للثآليل التناسلية؟"},"options":[{"letter":"A","en":"Soft, moist, cauliflower-like genital lesions","ar":"آفات تناسلية لينة رطبة تشبه القرنبيط"},{"letter":"B","en":"Dermatomal painful vesicles","ar":"حويصلات مؤلمة قطاعية"},{"letter":"C","en":"Centripetal vesicles in crops","ar":"حويصلات مركزية على دفعات"},{"letter":"D","en":"Slapped-cheek erythema","ar":"احمرار الخدين كالصفعة"}],"correct":"A","explanation":{"en":"Genital warts are typically soft, moist, papillomatous, and cauliflower-like.","ar":"تكون الثآليل التناسلية عادةً لينة ورطبة وحليمية وتشبه القرنبيط."},"reasoning":{"en":"Morphology and location guide diagnosis, but atypical or pigmented lesions may require biopsy.","ar":"يوجه الشكل والمكان التشخيص، لكن الآفات غير النمطية أو المصطبغة قد تحتاج خزعة."},"image":null},{"id":"Q028","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 129","question":{"en":"What feature helps distinguish a plantar wart from a corn after paring?","ar":"ما السمة التي تساعد على تمييز الثؤلول الأخمصي عن مسمار القدم بعد الكشط؟"},"options":[{"letter":"A","en":"Pinpoint bleeding from thrombosed capillaries","ar":"نزف نقطي من شعيرات متخثرة"},{"letter":"B","en":"Complete preservation of skin lines","ar":"الحفاظ الكامل على خطوط الجلد"},{"letter":"C","en":"No tenderness with pressure","ar":"عدم وجود ألم مع الضغط"},{"letter":"D","en":"Bright coral fluorescence","ar":"فلورة مرجانية زاهية"}],"correct":"A","explanation":{"en":"Paring a wart may reveal black dots or pinpoint bleeding caused by thrombosed capillaries.","ar":"قد يكشف كشط الثؤلول نقاطًا سوداء أو نزفًا نقطيًا نتيجة شعيرات دموية متخثرة."},"reasoning":{"en":"Warts interrupt dermatoglyphics and contain vascular dots, unlike a simple corn.","ar":"تقطع الثآليل خطوط الجلد وتحتوي نقاطًا وعائية بخلاف مسمار القدم البسيط."},"image":null},{"id":"Q029","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 130","question":{"en":"Which wart type commonly appears as multiple smooth, flat-topped papules on the face or dorsal hands?","ar":"أي نوع من الثآليل يظهر غالبًا كحطاطات متعددة ملساء مسطحة القمة على الوجه أو ظهر اليدين؟"},"options":[{"letter":"A","en":"Flat warts","ar":"الثآليل المسطحة"},{"letter":"B","en":"Plantar warts","ar":"الثآليل الأخمصية"},{"letter":"C","en":"Filiform genital warts only","ar":"الثآليل التناسلية الخيطية فقط"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"Verruca plana presents as numerous small, smooth, flat-topped papules, often on the face or hands.","ar":"تظهر الثآليل المسطحة كحطاطات صغيرة متعددة ملساء ومسطحة القمة غالبًا على الوجه أو اليدين."},"reasoning":{"en":"The smooth surface and multiplicity distinguish them from rough common warts.","ar":"يميز السطح الأملس والتعدد هذه الآفات عن الثآليل الشائعة الخشنة."},"image":null},{"id":"Q030","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 131","question":{"en":"Which treatment is commonly first-line for many non-genital cutaneous warts?","ar":"أي علاج يُستخدم عادةً كخط أول لكثير من الثآليل الجلدية غير التناسلية؟"},"options":[{"letter":"A","en":"Topical salicylic acid","ar":"حمض الساليسيليك موضعيًا"},{"letter":"B","en":"IV acyclovir","ar":"أسيكلوفير وريدي"},{"letter":"C","en":"Oral fluconazole","ar":"فلوكونازول فموي"},{"letter":"D","en":"Systemic penicillin","ar":"بنسلين جهازي"}],"correct":"A","explanation":{"en":"Salicylic acid is effective, inexpensive, and suitable for home treatment when used consistently.","ar":"حمض الساليسيليك فعال وقليل التكلفة ومناسب للعلاج المنزلي عند استخدامه بانتظام."},"reasoning":{"en":"Keratolysis removes infected keratin gradually while minimizing procedural pain.","ar":"يزيل التحلل القرني الكيراتين المصاب تدريجيًا مع تقليل ألم الإجراءات."},"image":null},{"id":"Q031","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 132","question":{"en":"Which patient-applied drug is used for external genital warts by stimulating local immunity?","ar":"أي دواء يطبقه المريض للثآليل التناسلية الخارجية عبر تنشيط المناعة الموضعية؟"},"options":[{"letter":"A","en":"Imiquimod","ar":"إيميكويمود"},{"letter":"B","en":"Calamine","ar":"كالامين"},{"letter":"C","en":"Acyclovir","ar":"أسيكلوفير"},{"letter":"D","en":"Selenium sulfide","ar":"سيلينيوم سلفايد"}],"correct":"A","explanation":{"en":"Imiquimod is an immune-response modifier used for selected external genital warts.","ar":"إيميكويمود مُعدل للاستجابة المناعية يُستخدم لبعض الثآليل التناسلية الخارجية."},"reasoning":{"en":"Treatment choice depends on lesion site, number, pregnancy status, cost, and the patient’s ability to apply therapy correctly.","ar":"يعتمد اختيار العلاج على المكان والعدد والحمل والتكلفة وقدرة المريض على التطبيق الصحيح."},"image":null},{"id":"Q032","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"MCQ","difficulty":"Medium","source":"PDF p. 128","question":{"en":"What is the primary preventive strategy against oncogenic HPV disease?","ar":"ما الاستراتيجية الوقائية الأساسية ضد أمراض HPV المسرطنة؟"},"options":[{"letter":"A","en":"HPV vaccination before exposure","ar":"التطعيم ضد HPV قبل التعرض"},{"letter":"B","en":"Daily systemic antibiotics","ar":"مضادات حيوية جهازية يومية"},{"letter":"C","en":"Avoiding all sunlight","ar":"تجنب الشمس تمامًا"},{"letter":"D","en":"Routine acyclovir prophylaxis","ar":"وقاية روتينية بأسيكلوفير"}],"correct":"A","explanation":{"en":"Vaccination prevents infection with important wart-causing and oncogenic HPV types.","ar":"يمنع التطعيم العدوى بأنماط مهمة مسببة للثآليل ومسرطنة من HPV."},"reasoning":{"en":"Vaccination is most effective before sexual exposure but does not replace recommended screening.","ar":"يكون التطعيم أكثر فعالية قبل التعرض الجنسي لكنه لا يلغي الفحوص الموصى بها."},"image":null},{"id":"Q033","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"MCQ","difficulty":"Medium","source":"PDF p. 137","question":{"en":"Which viruses most commonly cause hand-foot-and-mouth disease?","ar":"ما الفيروسات الأكثر تسببًا في مرض اليد والقدم والفم؟"},"options":[{"letter":"A","en":"Coxsackievirus A16 and enterovirus A71","ar":"كوكساكي A16 وإنتروفيروس A71"},{"letter":"B","en":"HSV-2 only","ar":"HSV-2 فقط"},{"letter":"C","en":"HPV 16 and 18","ar":"HPV 16 و18"},{"letter":"D","en":"Parvovirus B19 only","ar":"بارفو B19 فقط"}],"correct":"A","explanation":{"en":"HFMD is usually caused by enteroviruses, particularly coxsackievirus A16 and EV-A71.","ar":"ينتج مرض اليد والقدم والفم غالبًا عن الفيروسات المعوية خاصة كوكساكي A16 وEV-A71."},"reasoning":{"en":"Identifying the enteroviral syndrome helps anticipate transmission and neurologic risk in EV-A71 outbreaks.","ar":"تحديد المتلازمة المعوية يساعد على توقع الانتقال وخطر المضاعفات العصبية في تفشيات EV-A71."},"image":null},{"id":"Q034","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"MCQ","difficulty":"Medium","source":"PDF p. 138","question":{"en":"Which distribution best supports HFMD?","ar":"أي توزيع يدعم تشخيص مرض اليد والقدم والفم؟"},"options":[{"letter":"A","en":"Oral ulcers with vesicles on hands and feet","ar":"قرح فموية مع حويصلات على اليدين والقدمين"},{"letter":"B","en":"Only unilateral thoracic vesicles","ar":"حويصلات صدرية أحادية الجانب فقط"},{"letter":"C","en":"Only scalp alopecia","ar":"فقد شعر بفروة الرأس فقط"},{"letter":"D","en":"Only genital cauliflower lesions","ar":"آفات تناسلية قرنبيطية فقط"}],"correct":"A","explanation":{"en":"HFMD combines oral enanthem with acral lesions on hands and feet, sometimes buttocks.","ar":"يجمع مرض اليد والقدم والفم بين طفح فموي وآفات طرفية على اليدين والقدمين وأحيانًا الأرداف."},"reasoning":{"en":"The combined oral-acral pattern is more specific than fever or sore throat alone.","ar":"النمط الفموي الطرفي المشترك أكثر نوعية من الحمى أو ألم الحلق وحدهما."},"image":null},{"id":"Q035","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"MCQ","difficulty":"Medium","source":"PDF p. 139","question":{"en":"How does herpangina usually differ from HFMD?","ar":"كيف تختلف الهربانجينا عادةً عن مرض اليد والقدم والفم؟"},"options":[{"letter":"A","en":"Posterior oral lesions without the typical hand and foot rash","ar":"آفات فموية خلفية دون الطفح المعتاد على اليدين والقدمين"},{"letter":"B","en":"It always causes genital warts","ar":"تسبب دائمًا ثآليل تناسلية"},{"letter":"C","en":"It is caused by VZV reactivation","ar":"سببها إعادة تنشيط VZV"},{"letter":"D","en":"It causes a slapped-cheek rash","ar":"تسبب طفح الخدود المصفوعة"}],"correct":"A","explanation":{"en":"Herpangina mainly affects the posterior oropharynx and generally lacks the acral exanthem of HFMD.","ar":"تصيب الهربانجينا أساسًا الجزء الخلفي من الفم والبلعوم وعادةً لا يصاحبها طفح طرفي كمرض اليد والقدم والفم."},"reasoning":{"en":"Oral lesion location and the presence or absence of acral lesions separate the syndromes.","ar":"يفصل مكان الآفات الفموية ووجود أو غياب الآفات الطرفية بين المتلازمتين."},"image":null},{"id":"Q036","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"MCQ","difficulty":"Medium","source":"PDF p. 141","question":{"en":"What is the usual treatment for uncomplicated HFMD?","ar":"ما العلاج المعتاد لمرض اليد والقدم والفم غير المعقد؟"},"options":[{"letter":"A","en":"Supportive hydration and analgesia","ar":"السوائل والمسكنات كعلاج داعم"},{"letter":"B","en":"Routine IV acyclovir","ar":"أسيكلوفير وريدي روتيني"},{"letter":"C","en":"Long-term antibiotics","ar":"مضادات حيوية طويلة المدى"},{"letter":"D","en":"Surgical excision of vesicles","ar":"استئصال الحويصلات جراحيًا"}],"correct":"A","explanation":{"en":"Uncomplicated HFMD is self-limited; maintaining hydration and controlling pain are central.","ar":"مرض اليد والقدم والفم غير المعقد محدود ذاتيًا، ويُعد الحفاظ على السوائل والسيطرة على الألم أساس العلاج."},"reasoning":{"en":"Painful oral lesions can reduce intake, so dehydration risk is more important than the skin lesions themselves.","ar":"قد تقلل القرح الفموية المؤلمة تناول السوائل، لذا يكون خطر الجفاف أهم من الآفات الجلدية نفسها."},"image":null},{"id":"Q037","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"MCQ","difficulty":"Medium","source":"PDF p. 140","question":{"en":"Which feature should raise concern for severe EV-A71 disease?","ar":"أي علامة تثير القلق من مرض شديد بسبب EV-A71؟"},"options":[{"letter":"A","en":"Neurologic symptoms such as myoclonus, lethargy, or weakness","ar":"أعراض عصبية مثل الرمع العضلي أو الخمول أو الضعف"},{"letter":"B","en":"Mild isolated pruritus","ar":"حكة بسيطة منفردة"},{"letter":"C","en":"One painless wart","ar":"ثؤلول واحد غير مؤلم"},{"letter":"D","en":"Stable freckles","ar":"نمش ثابت"}],"correct":"A","explanation":{"en":"EV-A71 can cause brainstem encephalitis and other neurologic complications.","ar":"قد يسبب EV-A71 التهاب جذع الدماغ ومضاعفات عصبية أخرى."},"reasoning":{"en":"Neurologic or cardiopulmonary signs change HFMD from routine outpatient care to urgent assessment.","ar":"تحول العلامات العصبية أو القلبية الرئوية الحالة من رعاية خارجية معتادة إلى تقييم عاجل."},"image":null},{"id":"Q038","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 146","question":{"en":"Which triad is typical of the measles prodrome?","ar":"ما الثلاثية النموذجية للطور البادري للحصبة؟"},"options":[{"letter":"A","en":"Cough, coryza, and conjunctivitis","ar":"السعال والرشح والتهاب الملتحمة"},{"letter":"B","en":"Ear pain, facial palsy, and vesicles","ar":"ألم الأذن وشلل الوجه والحويصلات"},{"letter":"C","en":"Dysuria, genital ulcers, and lymphadenopathy","ar":"عسر التبول والقرح التناسلية وتضخم العقد"},{"letter":"D","en":"Arthritis, slapped cheeks, and anemia","ar":"التهاب مفاصل وخدود مصعوفة وأنيميا"}],"correct":"A","explanation":{"en":"The classic measles prodrome consists of cough, coryza, conjunctivitis, and fever.","ar":"يتكون الطور البادري الكلاسيكي للحصبة من السعال والرشح والتهاب الملتحمة والحمى."},"reasoning":{"en":"The “three Cs” before the rash are a high-yield clue, especially with exposure or absent vaccination.","ar":"تعد العلامات الثلاث قبل الطفح دليلًا مهمًا خاصة مع التعرض أو عدم التطعيم."},"image":null},{"id":"Q039","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 147","question":{"en":"Where are Koplik spots found?","ar":"أين توجد بقع كوبليك؟"},"options":[{"letter":"A","en":"Buccal mucosa opposite the molars","ar":"الغشاء المخاطي للخد مقابل الأضراس"},{"letter":"B","en":"Nail matrix","ar":"مصفوفة الظفر"},{"letter":"C","en":"Sole only","ar":"أخمص القدم فقط"},{"letter":"D","en":"External auditory canal","ar":"القناة السمعية الخارجية"}],"correct":"A","explanation":{"en":"Koplik spots are tiny bluish-white lesions on erythematous buccal mucosa, often opposite the molars.","ar":"بقع كوبليك نقاط بيضاء مزرقة صغيرة على مخاطية الخد المحمرة غالبًا مقابل الأضراس."},"reasoning":{"en":"They may precede the skin rash and provide an early, characteristic diagnostic sign.","ar":"قد تسبق الطفح الجلدي وتوفر علامة تشخيصية مبكرة ومميزة."},"image":null},{"id":"Q040","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 148","question":{"en":"What is the usual direction of spread of the measles rash?","ar":"ما الاتجاه المعتاد لانتشار طفح الحصبة؟"},"options":[{"letter":"A","en":"From hairline/face downward to trunk and extremities","ar":"من خط الشعر والوجه إلى أسفل نحو الجذع والأطراف"},{"letter":"B","en":"From soles upward only","ar":"من الأخمص إلى أعلى فقط"},{"letter":"C","en":"Along one dermatome","ar":"على قطاع عصبي واحد"},{"letter":"D","en":"Limited to genital folds","ar":"محدود بثنيات الأعضاء التناسلية"}],"correct":"A","explanation":{"en":"The maculopapular rash begins on the face or hairline and spreads cephalocaudally.","ar":"يبدأ الطفح البقعي الحطاطي على الوجه أو خط الشعر وينتشر من أعلى لأسفل."},"reasoning":{"en":"The sequence of spread distinguishes measles from several other viral exanthems.","ar":"يميز تسلسل الانتشار الحصبة عن عدة طفوح فيروسية أخرى."},"image":null},{"id":"Q041","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 149","question":{"en":"Which isolation precaution is essential for suspected measles in a healthcare setting?","ar":"أي احتياط عزل أساسي عند الاشتباه في الحصبة داخل منشأة صحية؟"},"options":[{"letter":"A","en":"Airborne precautions","ar":"احتياطات الانتقال الهوائي"},{"letter":"B","en":"No isolation","ar":"لا حاجة للعزل"},{"letter":"C","en":"Only food precautions","ar":"احتياطات الطعام فقط"},{"letter":"D","en":"Only reverse isolation without a mask","ar":"عزل عكسي فقط دون كمامة"}],"correct":"A","explanation":{"en":"Measles is highly contagious through airborne transmission.","ar":"الحصبة شديدة العدوى عبر الانتقال الهوائي."},"reasoning":{"en":"Immediate airborne isolation protects susceptible patients and staff before laboratory confirmation.","ar":"يحمي العزل الهوائي الفوري المرضى والطاقم القابلين للعدوى قبل التأكيد المخبري."},"image":null},{"id":"Q042","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 151","question":{"en":"Which vitamin is recommended for children with measles to reduce morbidity and mortality?","ar":"أي فيتامين يُوصى به للأطفال المصابين بالحصبة لتقليل المضاعفات والوفيات؟"},"options":[{"letter":"A","en":"Vitamin A","ar":"فيتامين أ"},{"letter":"B","en":"Vitamin K only","ar":"فيتامين ك فقط"},{"letter":"C","en":"Vitamin B12 only","ar":"فيتامين ب12 فقط"},{"letter":"D","en":"Vitamin E mega-dose","ar":"جرعة ضخمة من فيتامين هـ"}],"correct":"A","explanation":{"en":"Vitamin A supplementation is recommended in pediatric measles, especially in severe disease or deficiency risk.","ar":"يُوصى بإعطاء فيتامين أ للأطفال المصابين بالحصبة خاصة في المرض الشديد أو خطر النقص."},"reasoning":{"en":"It supports epithelial and immune function and reduces serious measles outcomes.","ar":"يدعم وظيفة الظهارة والمناعة ويقلل النتائج الخطيرة للحصبة."},"image":null},{"id":"Q043","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"MCQ","difficulty":"Medium","source":"PDF p. 153","question":{"en":"What is the most effective population-level prevention of measles?","ar":"ما أكثر وسائل الوقاية المجتمعية فعالية ضد الحصبة؟"},"options":[{"letter":"A","en":"Two-dose measles-containing vaccination","ar":"جرعتان من لقاح يحتوي مكون الحصبة"},{"letter":"B","en":"Daily acyclovir","ar":"أسيكلوفير يومي"},{"letter":"C","en":"Topical antiseptics","ar":"مطهرات موضعية"},{"letter":"D","en":"Avoiding dairy products","ar":"تجنب منتجات الألبان"}],"correct":"A","explanation":{"en":"High two-dose vaccine coverage prevents disease and interrupts transmission.","ar":"يمنع ارتفاع تغطية اللقاح بجرعتين المرض ويقطع سلسلة الانتقال."},"reasoning":{"en":"Because measles is exceptionally contagious, individual and community protection depend on vaccination.","ar":"لأن الحصبة شديدة العدوى بصورة استثنائية، تعتمد الحماية الفردية والمجتمعية على التطعيم."},"image":null},{"id":"Q044","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"MCQ","difficulty":"Medium","source":"PDF p. 155","question":{"en":"Which lymph-node pattern is particularly suggestive of rubella?","ar":"أي نمط لتضخم العقد اللمفاوية يوحي خاصة بالحصبة الألمانية؟"},"options":[{"letter":"A","en":"Postauricular and suboccipital lymphadenopathy","ar":"تضخم العقد خلف الأذن وتحت القذال"},{"letter":"B","en":"Only inguinal nodes with abscesses","ar":"العقد الأربية فقط مع خراجات"},{"letter":"C","en":"Hilar lymphadenopathy only","ar":"العقد النقيرية فقط"},{"letter":"D","en":"No lymph-node involvement ever","ar":"لا يحدث تضخم عقدي أبدًا"}],"correct":"A","explanation":{"en":"Tender postauricular, posterior cervical, and suboccipital nodes are classic for rubella.","ar":"تعد العقد المؤلمة خلف الأذن وخلف العنق وتحت القذال نموذجية للحصبة الألمانية."},"reasoning":{"en":"This pattern helps separate a mild rubelliform rash from other exanthems.","ar":"يساعد هذا النمط على تمييز طفح الحصبة الألمانية الخفيف عن الطفوح الأخرى."},"image":null},{"id":"Q045","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"MCQ","difficulty":"Medium","source":"PDF p. 156","question":{"en":"Why is rubella infection particularly important during early pregnancy?","ar":"لماذا تُعد عدوى الحصبة الألمانية مهمة بصورة خاصة في الحمل المبكر؟"},"options":[{"letter":"A","en":"Risk of congenital rubella syndrome","ar":"خطر متلازمة الحصبة الألمانية الخلقية"},{"letter":"B","en":"It always causes maternal shingles","ar":"تسبب دائمًا حزامًا ناريًا للأم"},{"letter":"C","en":"It causes plantar warts in the fetus","ar":"تسبب ثآليل أخمصية للجنين"},{"letter":"D","en":"It has no fetal consequences","ar":"لا عواقب جنينية لها"}],"correct":"A","explanation":{"en":"Maternal rubella, especially early in gestation, can cause severe congenital defects.","ar":"قد تسبب الحصبة الألمانية لدى الأم خاصة في بدايات الحمل عيوبًا خلقية شديدة."},"reasoning":{"en":"Pregnancy status changes counseling, testing, public-health action, and prevention priorities.","ar":"تغير حالة الحمل التوعية والفحوص وإجراءات الصحة العامة وأولويات الوقاية."},"image":null},{"id":"Q046","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"MCQ","difficulty":"Medium","source":"PDF p. 157","question":{"en":"Which vaccine prevents rubella?","ar":"أي لقاح يقي من الحصبة الألمانية؟"},"options":[{"letter":"A","en":"MMR vaccine","ar":"لقاح MMR"},{"letter":"B","en":"BCG vaccine","ar":"لقاح BCG"},{"letter":"C","en":"Rabies vaccine","ar":"لقاح السعار"},{"letter":"D","en":"Hepatitis B vaccine only","ar":"لقاح التهاب الكبد ب فقط"}],"correct":"A","explanation":{"en":"Rubella prevention is achieved with the live attenuated MMR vaccine.","ar":"تتحقق الوقاية من الحصبة الألمانية بلقاح MMR الحي المضعف."},"reasoning":{"en":"Vaccinating before pregnancy prevents congenital rubella syndrome; live vaccine is avoided during pregnancy.","ar":"يمنع التطعيم قبل الحمل متلازمة الحصبة الألمانية الخلقية، ويُتجنب اللقاح الحي أثناء الحمل."},"image":null},{"id":"Q047","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"MCQ","difficulty":"Medium","source":"PDF p. 158","question":{"en":"What is the causative agent of erythema infectiosum?","ar":"ما العامل المسبب للحمامى المعدية «المرض الخامس»؟"},"options":[{"letter":"A","en":"Parvovirus B19","ar":"بارفو فيروس B19"},{"letter":"B","en":"HSV-1","ar":"HSV-1"},{"letter":"C","en":"VZV","ar":"VZV"},{"letter":"D","en":"HPV-6","ar":"HPV-6"}],"correct":"A","explanation":{"en":"Erythema infectiosum is caused by parvovirus B19.","ar":"تنتج الحمامى المعدية عن بارفو فيروس B19."},"reasoning":{"en":"The diagnosis links the rash to risks such as transient aplastic crisis and fetal complications.","ar":"يربط التشخيص الطفح بمخاطر مثل الأزمة اللاتنسجية العابرة ومضاعفات الجنين."},"image":null},{"id":"Q048","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"MCQ","difficulty":"Medium","source":"PDF p. 158","question":{"en":"Which rash pattern is classic in a child with fifth disease?","ar":"أي نمط طفح كلاسيكي لدى طفل مصاب بالمرض الخامس؟"},"options":[{"letter":"A","en":"Slapped-cheek erythema followed by a lacy body rash","ar":"احمرار الخدين كالصفعة يتبعه طفح شبكي على الجسم"},{"letter":"B","en":"Dermatomal vesicles","ar":"حويصلات قطاعية"},{"letter":"C","en":"Cauliflower genital lesions","ar":"آفات تناسلية تشبه القرنبيط"},{"letter":"D","en":"Pearly umbilicated papules","ar":"حطاطات لؤلؤية منقرة"}],"correct":"A","explanation":{"en":"The facial erythema is followed by a reticular or lacy eruption on the trunk and limbs.","ar":"يتبع احمرار الوجه طفح شبكي أو دانتلي على الجذع والأطراف."},"reasoning":{"en":"The sequence is characteristic and often appears after the viremic contagious phase.","ar":"التسلسل مميز وغالبًا يظهر بعد مرحلة الفيروس في الدم الأكثر عدوى."},"image":null},{"id":"Q049","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"MCQ","difficulty":"Medium","source":"PDF p. 160","question":{"en":"Which patient is at greatest risk of transient aplastic crisis from parvovirus B19?","ar":"أي مريض أكثر عرضة لأزمة لاتنسجية عابرة بسبب بارفو B19؟"},"options":[{"letter":"A","en":"A patient with chronic hemolytic anemia","ar":"مريض بأنيميا انحلالية مزمنة"},{"letter":"B","en":"A healthy adult with one wart","ar":"بالغ سليم لديه ثؤلول واحد"},{"letter":"C","en":"A child with isolated tinea pedis","ar":"طفل لديه تينيا قدم فقط"},{"letter":"D","en":"A patient with allergic rhinitis only","ar":"مريض بحساسية أنف فقط"}],"correct":"A","explanation":{"en":"Parvovirus suppresses erythroid precursors, which is dangerous when red-cell turnover is already high.","ar":"يثبط بارفو طلائع كريات الدم الحمراء، وهو خطر عندما يكون معدل تكسير الكريات مرتفعًا أصلًا."},"reasoning":{"en":"Underlying hemolysis converts a brief production pause into a potentially severe anemia.","ar":"تحول الأنيميا الانحلالية توقف الإنتاج القصير إلى أنيميا قد تكون شديدة."},"image":null},{"id":"Q050","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"MCQ","difficulty":"Medium","source":"PDF p. 161","question":{"en":"Which lesion is characteristic of molluscum contagiosum?","ar":"أي آفة تميز المليساء المعدية؟"},"options":[{"letter":"A","en":"Pearly dome-shaped papule with central umbilication","ar":"حطاطة لؤلؤية قُبّبية ذات تنقر مركزي"},{"letter":"B","en":"Large painful dermatomal bulla","ar":"فقاعة قطاعية كبيرة مؤلمة"},{"letter":"C","en":"Annular scaly plaque with central clearing","ar":"لويحة حلقية متقشرة بتفريغ مركزي"},{"letter":"D","en":"Honey-colored crust","ar":"قشرة بلون العسل"}],"correct":"A","explanation":{"en":"Molluscum produces smooth, firm, pearly papules with a central dell.","ar":"تسبب المليساء حطاطات ملساء صلبة لؤلؤية ذات انخفاض مركزي."},"reasoning":{"en":"Central umbilication is the key morphological clue.","ar":"التنقر المركزي هو العلامة الشكلية الأساسية."},"image":null}];
